{
  "sentences": [
    {
      "text": "你來台灣多久了？",
      "pinyin": "Nǐ lái Táiwān duō jiǔ le?",
      "pinyin_numeric": "ni3 lai2 tai2 wan1 duo1 jiu3 le0",
      "translation_en": "How long have you been in Taiwan?",
      "translation_ko": "대만에 온 지 얼마나 되었어요?"
    },
    {
      "text": "我來台灣兩年了。",
      "pinyin": "Wǒ lái Táiwān liǎng nián le.",
      "pinyin_numeric": "wo3 lai2 tai2 wan1 liang3 nian2 le0",
      "translation_en": "I have been in Taiwan for two years.",
      "translation_ko": "저는 대만에 온 지 2년 되었어요."
    },
    {
      "text": "你學中文多久了？",
      "pinyin": "Nǐ xué Zhōngwén duō jiǔ le?",
      "pinyin_numeric": "ni3 xue2 zhong1 wen2 duo1 jiu3 le0",
      "translation_en": "How long have you been learning Chinese?",
      "translation_ko": "중국어를 배운 지 얼마나 되었어요?"
    },
    {
      "text": "我學中文半年了。",
      "pinyin": "Wǒ xué Zhōngwén bàn nián le.",
      "pinyin_numeric": "wo3 xue2 zhong1 wen2 ban4 nian2 le0",
      "translation_en": "I have been learning Chinese for half a year.",
      "translation_ko": "저는 중국어를 배운 지 반 년 되었어요."
    },
    {
      "text": "你從哪裡來的？",
      "pinyin": "Nǐ cóng nǎlǐ lái de?",
      "pinyin_numeric": "ni3 cong2 na3 li3 lai2 de0",
      "translation_en": "Where are you from?",
      "translation_ko": "어디에서 오셨어요?"
    },
    {
      "text": "我從美國來的，我的故鄉在紐約。",
      "pinyin": "Wǒ cóng Měiguó lái de, wǒ de gùxiāng zài Niǔyuē.",
      "pinyin_numeric": "wo3 cong2 mei3 guo2 lai2 de0, wo3 de0 gu4 xiang1 zai4 niu3 yue1",
      "translation_en": "I am from the United States; my hometown is New York.",
      "translation_ko": "저는 미국에서 왔고, 고향은 뉴욕이에요."
    },
    {
      "sentence": "你為什麼想學中文？",
      "pinyin": "Nǐ wèishénme xiǎng xué Zhōngwén?",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xiang3 xue2 zhong1 wen2",
      "translation_en": "Why do you want to learn Chinese?",
      "translation_ko": "왜 중국어를 배우고 싶어요?"
    },
    {
      "text": "因為我喜歡台灣的文化，所以想學中文。",
      "pinyin": "Yīnwèi wǒ xǐhuān Táiwān de wénhuà, suǒyǐ xiǎng xué Zhōngwén.",
      "pinyin_numeric": "yin1 wei4 wo3 xi3 huan1 tai2 wan1 de0 wen2 hua4, suo3 yi3 xiang3 xue2 zhong1 wen2",
      "translation_en": "Because I like Taiwanese culture, I want to learn Chinese.",
      "translation_ko": "대만 문화가 좋아서 중국어를 배우고 싶어요."
    },
    {
      "text": "你現在做什麼工作？",
      "pinyin": "Nǐ xiànzài zuò shénme gōngzuò?",
      "pinyin_numeric": "ni3 xian4 zai4 zuo4 shen2 me0 gong1 zuo4",
      "translation_en": "What do you do for work now?",
      "translation_ko": "지금 무슨 일을 하세요?"
    },
    {
      "text": "我現在是學生，在台灣留學。",
      "pinyin": "Wǒ xiànzài shì xuéshēng, zài Táiwān liúxué.",
      "pinyin_numeric": "wo3 xian4 zai4 shi4 xue2 sheng1, zai4 tai2 wan1 liu2 xue2",
      "translation_en": "I am a student now, studying abroad in Taiwan.",
      "translation_ko": "저는 지금 학생이고, 대만에서 유학 중이에요."
    }
  ]
}
